SELECT AVG(battery_health) AS average_critical_battery_health
FROM ups_status
WHERE battery_health = 'critical';

SELECT battery_capacity
FROM ups_units
WHERE status = 'online';

SELECT * 
FROM sites
WHERE site_manager LIKE 'A%' AND site_status = 'active';

SELECT ups_id, light_id
FROM ups_status
WHERE state_id > 5;

SELECT AVG(battery_capacity) AS AverageBatteryCapacity
FROM ups_units
WHERE status = 'online' AND current_load > 50;

SELECT 
  (SELECT MIN(installation_date) FROM ups_units) AS oldest_ups_installation_date,
  (SELECT AVG(site_count) 
   FROM (
     SELECT location, COUNT(*) AS site_count 
     FROM sites 
     GROUP BY location
   )
  ) AS average_sites_per_location,
  (SELECT COUNT(*) FROM alarms WHERE acknowledged = 0 AND resolved = 0) AS active_unacknowledged_alarms;
